# 数据恢复脚本：
# 1. cd ~/mysite
# 2. 复制下面整段代码到 Console 粘贴运行
import base64, tarfile, io, os
os.chdir(os.path.expanduser("~/mysite"))
data=base64.b64decode("")
t=tarfile.open(fileobj=io.BytesIO(data),mode="r:gz")
t.extractall(".")
print("✅ 恢复成功！")
